def preparation_stage_timing_fields(fields: dict[str, Any]) -> dict[str, str]:
    return {
        field: str(fields[field])
        for field in PREPARATION_STAGE_TIMING_FIELDS
        if field in fields and fields[field] not in (None, "", "none")
    }


def preparation_engine_millis(fields: dict[str, Any], fallback_millis: float) -> float:
    for field in (
        "prepare_batch_prepared_state_lookup_or_create_micros",
        "prepare_batch_preparation_micros",
        "prepared_state_lookup_or_create_micros",
        "compatibility_to_vortex_import_micros",
        "inclusive_compatibility_to_vortex_import_micros",
    ):
        value = fields.get(field)
        if value in (None, "", "none"):
            continue
        try:
            return round(float(value) / 1000.0, 4)
        except (TypeError, ValueError):
            continue
    exclusive_fields = (
        "exclusive_source_admission_micros",
        "exclusive_source_read_micros",
        "exclusive_source_parse_or_decode_micros",
        "exclusive_source_to_vortex_array_micros",
        "exclusive_vortex_write_micros",
        "exclusive_vortex_digest_micros",
        "exclusive_vortex_reopen_verify_micros",
    )
    exclusive_values: list[float] = []
    for field in exclusive_fields:
        value = fields.get(field)
        if value in (None, "", "none"):
            continue
        try:
            exclusive_values.append(float(value))
        except (TypeError, ValueError):
            exclusive_values = []
            break
    if exclusive_values:
        return round(sum(exclusive_values) / 1000.0, 4)
    return round(fallback_millis, 4)


def preparation_route_total_millis(fields: dict[str, Any], fallback_millis: float) -> float:
    for field in (
        "prepare_batch_prepare_route_total_micros",
        "total_runtime_micros",
        "inclusive_total_runtime_micros",
    ):
        value = fields.get(field)
        if value in (None, "", "none"):
            continue
        try:
            return round(float(value) / 1000.0, 4)
        except (TypeError, ValueError):
            continue
    return round(fallback_millis, 4)


def round_float(value: Any) -> float:
    if value is None:
        return 0.0
    number = float(value)
    if math.isnan(number):
        return 0.0
    return round(number, CORRECTNESS_FLOAT_DIGITS)


def normalize_scalar_result(row_count: Any, metric_sum: Any) -> dict[str, Any]:
    return {"row_count": int(row_count), "metric_sum": round_float(metric_sum)}


def parse_output_fields(payload: dict[str, Any]) -> dict[str, str]:
    return {
        str(field.get("key")): str(field.get("value"))
        for field in payload.get("fields", [])
        if isinstance(field, dict) and "key" in field
    }


def parse_optional_int(value: Any) -> int | None:
    if value is None or value == "none" or value == "":
        return None
    try:
        return int(value)
    except (TypeError, ValueError):
        return None


def parse_optional_float(value: Any) -> float | None:
    if value is None or value == "none" or value == "":
        return None
    try:
        return float(value)
    except (TypeError, ValueError):
        return None


def parse_optional_bool(value: Any) -> bool | None:
    if value is None or value == "none" or value == "":
        return None
    text = str(value).strip().lower()
    if text == "true":
        return True
    if text == "false":
        return False
    return None


def prepared_native_vortex_lifecycle_metrics(evidence: dict[str, str]) -> dict[str, Any]:
    metrics: dict[str, Any] = {}
    for field in PREPARED_NATIVE_VORTEX_LIFECYCLE_FIELDS:
        if field not in evidence:
            continue
        value = evidence.get(field)
        if field in PREPARED_NATIVE_VORTEX_LIFECYCLE_BOOL_FIELDS:
            metrics[field] = parse_optional_bool(value)
        elif field in PREPARED_NATIVE_VORTEX_LIFECYCLE_INT_FIELDS:
            metrics[field] = parse_optional_int(value)
        else:
            metrics[field] = value
    return metrics


def first_meaningful_field(*values: Any) -> Any:
    for value in values:
        if value is not None and value != "" and value != "none":
            return value
    return None


