def route_shape_row_count_class(row_count: int | None) -> str:
    if row_count is None:
        return "unknown_rows"
    if row_count <= 1_000:
        return "tiny_smoke_rows"
    if row_count <= 100_000:
        return "local_smoke_rows"
    if row_count <= 10_000_000:
        return "local_claim_grade_rows"
    return "larger_than_local_claim_grade_rows"


def route_shape_source_file_shape(paths: DatasetPaths, scenario: str, data_format: str) -> str:
    if data_format == SHARDLOOM_VORTEX_FORMAT:
        return "existing_vortex_input"
    source_paths = source_state_paths(paths, scenario, data_format)
    if scenario == "many-small-files scan" and len(source_paths) > 1:
        return "split_fact_files_plus_dim"
    if scenario == "small change over large base" and len(source_paths) > 2:
        return "single_fact_single_dim_plus_cdc_delta"
    if len(source_paths) == 1:
        return "single_source_file"
    if len(source_paths) == 2:
        return "single_fact_single_dim"
    if len(source_paths) > 2:
        return "multi_source_file_set"
    return "no_local_source_file"


def route_shape_metadata(
    engine: str,
    paths: DatasetPaths,
    scenario: str,
    data_format: str,
    *,
    status: str,
    metrics: dict[str, Any],
    execution_mode: dict[str, Any],
    evidence: dict[str, Any] | None = None,
) -> dict[str, Any]:
    evidence = evidence or {}
    selected_mode = str(execution_mode.get("selected_execution_mode") or "unknown")
    is_shardloom = is_shardloom_engine(engine)
    if not is_shardloom:
        route_status = "external_baseline_only"
    elif status in UNSUPPORTED_ROW_STATUSES:
        route_status = "unsupported"
    elif shardloom_blocked_non_execution_status(status):
        route_status = "blocked"
    else:
        route_status = "route_total_metadata_complete"
    route_lane_id = route_lane_id_for_result(engine, selected_mode)
    route_family = route_family_for_result(engine, selected_mode)
    row_count = parse_optional_int(metrics.get("rows_scanned"))
    return {
        "route_shape_stratification_schema_version": first_meaningful_field(
            evidence.get("route_shape_stratification_schema_version"),
            "shardloom.traditional_analytics.route_shape_stratification.v1",
        ),
        "route_shape_status": first_meaningful_field(
            evidence.get("route_shape_status"),
            route_status,
        ),
        "route_shape_route_lane_id": route_lane_id,
        "route_shape_route_family": route_family,
        "route_shape_start_state": first_meaningful_field(
            route_start_state_for_result(engine, selected_mode),
        ),
        "route_shape_end_state": first_meaningful_field(
            evidence.get("route_shape_end_state"),
            "result_sink"
            if parse_optional_bool(metrics.get("computed_result_sink_written")) is True
            else "inline_result",
        ),
        "route_shape_row_count_class": first_meaningful_field(
            evidence.get("route_shape_row_count_class"),
            route_shape_row_count_class(row_count),
        ),
        "route_shape_source_file_shape": first_meaningful_field(
            evidence.get("route_shape_source_file_shape"),
            route_shape_source_file_shape(paths, scenario, data_format),
        ),
        "route_shape_source_format": first_meaningful_field(
            evidence.get("route_shape_source_format"),
            data_format,
        ),
        "route_shape_timing_total_field": first_meaningful_field(
            evidence.get("route_shape_timing_total_field"),
            "total_runtime_millis",
        ),
        "route_shape_stage_attribution_scope": first_meaningful_field(
            evidence.get("route_shape_stage_attribution_scope"),
            "diagnostic_stage_fields_only_route_total_authoritative",
        ),
        "route_shape_includes_preparation": (
            parse_optional_bool(evidence.get("route_shape_includes_preparation"))
            if evidence.get("route_shape_includes_preparation") is not None
            else bool(execution_mode.get("vortex_prepare_included"))
        ),
        "route_shape_includes_query": (
            parse_optional_bool(evidence.get("route_shape_includes_query"))
            if evidence.get("route_shape_includes_query") is not None
            else selected_mode != "external_baseline_only"
        ),
        "route_shape_includes_output": (
            parse_optional_bool(evidence.get("route_shape_includes_output"))
            if evidence.get("route_shape_includes_output") is not None
            else metrics.get("result_sink_write_millis") is not None
        ),
        "route_shape_includes_evidence": (
            parse_optional_bool(evidence.get("route_shape_includes_evidence"))
            if evidence.get("route_shape_includes_evidence") is not None
            else is_shardloom
        ),
        "route_shape_fallback_attempted": (
            parse_optional_bool(evidence.get("route_shape_fallback_attempted")) is True
        ),
        "route_shape_external_engine_invoked": (
            parse_optional_bool(evidence.get("route_shape_external_engine_invoked")) is True
        ),
        "route_shape_claim_boundary": first_meaningful_field(
            evidence.get("route_shape_claim_boundary"),
            "route-shape stratification records lane, start/end state, row-count class, and source-file shape for interpreting route totals only; stage fields remain diagnostic and no performance, production, SQL/DataFrame, object-store/lakehouse, Foundry, package, release, or Spark-displacement claim is authorized"
            if is_shardloom
            else "external baselines are comparison rows only and cannot satisfy ShardLoom route-shape evidence",
        ),
    }


def route_lane_id_for_result(engine: str, selected_mode: str) -> str:
    if engine == "shardloom":
        return "cold_certified_route"
    if engine == "shardloom-prepare-batch":
        return "prepare_once_batch"
    if engine == "shardloom-prepared-vortex":
        return "warm_prepared_query"
    if engine == "shardloom-vortex":
        return "native_vortex_query"
    if engine == "shardloom-direct-transient":
        return "direct_transient_route"
    if selected_mode == "external_baseline_only":
        return "external_baseline_end_to_end"
    return selected_mode


def route_family_for_mode(selected_mode: str) -> str:
    return {
        "compatibility_import_certified": "raw_compatibility_source_to_certified_vortex_ingest",
        "prepared_vortex": "vortex_prepared_state_to_prepared_query",
        "native_vortex": "existing_vortex_input_to_native_query",
        "direct_compatibility_transient": "raw_compatibility_direct_transient",
        "external_baseline_only": "external_baseline_raw_source",
    }.get(selected_mode, "unknown_route_family")


def route_family_for_result(engine: str, selected_mode: str) -> str:
    if engine == "shardloom":
        return "raw_compatibility_source_to_certified_vortex_ingest"
    if engine == "shardloom-prepare-batch":
        return "raw_compatibility_source_to_prepare_once_batch"
    return route_family_for_mode(selected_mode)


def route_start_state_for_mode(selected_mode: str) -> str:
    return {
        "compatibility_import_certified": "raw_compat_source",
        "direct_compatibility_transient": "raw_compat_source",
        "prepared_vortex": "VortexPreparedState",
        "native_vortex": "Vortex",
        "external_baseline_only": "raw_compat_source",
    }.get(selected_mode, "unknown")


def route_start_state_for_result(engine: str, selected_mode: str) -> str:
    if engine in {"shardloom", "shardloom-prepare-batch", "shardloom-direct-transient"}:
        return "raw_compat_source"
    return route_start_state_for_mode(selected_mode)


def source_to_vortex_array_guard_metadata(
    engine: str,
    *,
    status: str,
    metrics: dict[str, Any],
    execution_mode: dict[str, Any],
    evidence: dict[str, Any] | None = None,
) -> dict[str, Any]:
    evidence = evidence or {}
    is_shardloom = is_shardloom_engine(engine)
    selected_mode = str(execution_mode.get("selected_execution_mode") or "unknown")
    record_batch_count = parse_optional_int(
        first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_record_batch_count"),
            metrics.get("vortex_array_build_record_batch_count"),
        )
    )
    manual_scalar_copy_avoided = parse_optional_bool(
        first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_manual_scalar_copy_avoided"),
            metrics.get("vortex_array_build_manual_scalar_copy_avoided"),
        )
    )
    if not is_shardloom:
        guard_status = "external_baseline_only"
    elif status in UNSUPPORTED_ROW_STATUSES:
        guard_status = "unsupported"
    elif shardloom_blocked_non_execution_status(status):
        guard_status = "blocked"
    elif selected_mode == "direct_compatibility_transient":
        guard_status = "not_applicable_direct_transient_no_vortex_array_build"
    elif selected_mode == "native_vortex":
        guard_status = "not_applicable_existing_vortex_input"
    elif selected_mode == "prepared_vortex" and engine != "shardloom-prepare-batch":
        guard_status = "not_applicable_prepared_state_precreated_before_timing"
    elif record_batch_count and record_batch_count > 0 and manual_scalar_copy_avoided is True:
        guard_status = "guarded_vortex_array_build"
    else:
        guard_status = "blocked_missing_array_build_guard_evidence"
    if engine in {"shardloom", "shardloom-prepare-batch"}:
        reported_guard_status = first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_status"),
            guard_status,
        )
    else:
        reported_guard_status = guard_status
    return {
        "source_to_vortex_array_guard_schema_version": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_schema_version"),
            "shardloom.traditional_analytics.source_to_vortex_array_guard.v1",
        ),
        "source_to_vortex_array_guard_status": reported_guard_status,
        "source_to_vortex_array_guard_input_layout": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_input_layout"),
            metrics.get("vortex_array_build_input_layout"),
            "not_applicable" if not is_shardloom else "not_reported",
        ),
        "source_to_vortex_array_guard_provider_kind": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_provider_kind"),
            metrics.get("vortex_array_build_provider_kind"),
            "not_applicable" if not is_shardloom else "not_reported",
        ),
        "source_to_vortex_array_guard_provider_surface": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_provider_surface"),
            metrics.get("vortex_array_build_provider_surface"),
            "not_applicable" if not is_shardloom else "not_reported",
        ),
        "source_to_vortex_array_guard_strategy": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_strategy"),
            metrics.get("vortex_array_build_strategy"),
            "not_applicable" if not is_shardloom else "not_reported",
        ),
        "source_to_vortex_array_guard_record_batch_count": record_batch_count or 0,
        "source_to_vortex_array_guard_manual_scalar_copy_avoided": (
            manual_scalar_copy_avoided is True
        ),
        "source_to_vortex_array_guard_exclusive_stage_field": (
            source_to_vortex_array_guard_benchmark_field(
                evidence.get("source_to_vortex_array_guard_exclusive_stage_field"),
                "exclusive_source_to_vortex_array_millis",
            )
        ),
        "source_to_vortex_array_guard_inclusive_parent_field": (
            source_to_vortex_array_guard_benchmark_field(
                evidence.get("source_to_vortex_array_guard_inclusive_parent_field"),
                "compatibility_to_vortex_import_millis",
            )
        ),
        "source_to_vortex_array_guard_inclusive_timing_scope": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_inclusive_timing_scope"),
            metrics.get("compatibility_to_vortex_import_timing_scope"),
            "external_baseline_only" if not is_shardloom else "not_reported",
        ),
        "source_to_vortex_array_guard_inclusive_not_exclusive_status": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_inclusive_not_exclusive_status"),
            "inclusive_compatibility_import_contains_source_read_parse_array_build_and_write"
            if is_shardloom
            else "external_baseline_only",
        ),
        "source_to_vortex_array_guard_regression_fixture": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_regression_fixture"),
            "compatibility_import_report_exposes_exclusive_route_timing_and_prepared_state"
            if is_shardloom
            else "external_baseline_only",
        ),
        "source_to_vortex_array_guard_fallback_attempted": (
            parse_optional_bool(
                evidence.get("source_to_vortex_array_guard_fallback_attempted")
            )
            is True
        ),
        "source_to_vortex_array_guard_external_engine_invoked": (
            parse_optional_bool(
                evidence.get("source_to_vortex_array_guard_external_engine_invoked")
            )
            is True
        ),
        "source_to_vortex_array_guard_claim_boundary": first_meaningful_field(
            evidence.get("source_to_vortex_array_guard_claim_boundary"),
            "source-to-Vortex-array guard evidence protects timing-label integrity only: vortex_array_build is an exclusive substage, compatibility import remains an inclusive bundle, and no standalone performance or superiority claim is authorized"
            if is_shardloom
            else "external baselines cannot satisfy ShardLoom source-to-array guard evidence",
        ),
    }


def operator_blocker_metadata(
    engine: str, evidence: dict[str, Any] | None = None
) -> dict[str, Any]:
    evidence = evidence or {}
    if any(field in evidence for field in OPERATOR_BLOCKER_MATRIX_FIELDS):
        return {
            "operator_execution_class": str(
                evidence.get("operator_execution_class") or "unsupported"
            ),
            "operator_admission_status": str(
                evidence.get("operator_admission_status") or "unsupported"
            ),
            "operator_blocker_id": str(evidence.get("operator_blocker_id") or "missing"),
            "operator_blocker_reason": str(
                evidence.get("operator_blocker_reason") or "missing"
            ),
            "operator_encoded_native_claim_allowed": (
                parse_optional_bool(evidence.get("operator_encoded_native_claim_allowed"))
                is True
            ),
            "operator_residual_native_used": (
                parse_optional_bool(evidence.get("operator_residual_native_used")) is True
            ),
            "operator_temporary_materialization_used": (
                parse_optional_bool(evidence.get("operator_temporary_materialization_used"))
                is True
            ),
            "operator_blocker_matrix_ref": evidence.get("operator_blocker_matrix_ref"),
        }
    if engine == "shardloom-direct-transient":
        return {
            "operator_execution_class": "residual_native",
            "operator_admission_status": "direct_transient_scoped",
            "operator_blocker_id": "gar-flow-2b.not_prepared_native",
            "operator_blocker_reason": "direct transient is scoped ShardLoom-native compute, not prepared/native Vortex operator evidence",
            "operator_encoded_native_claim_allowed": False,
            "operator_residual_native_used": True,
            "operator_temporary_materialization_used": False,
            "operator_blocker_matrix_ref": "operator-blocker://traditional_analytics/direct_transient",
        }
    if is_shardloom_engine(engine):
        return {
            "operator_execution_class": "unsupported",
            "operator_admission_status": "not_executed",
            "operator_blocker_id": "gar-flow-2b.operator_evidence_missing",
            "operator_blocker_reason": "operator blocker evidence was not emitted",
            "operator_encoded_native_claim_allowed": False,
            "operator_residual_native_used": False,
            "operator_temporary_materialization_used": False,
            "operator_blocker_matrix_ref": None,
        }
    return {
        "operator_execution_class": "external_baseline_only",
        "operator_admission_status": "external_baseline_only",
        "operator_blocker_id": "external_baseline_only",
        "operator_blocker_reason": "external rows are comparison baselines, not ShardLoom operator evidence",
        "operator_encoded_native_claim_allowed": False,
        "operator_residual_native_used": False,
        "operator_temporary_materialization_used": False,
        "operator_blocker_matrix_ref": None,
    }


def work_avoidance_metric_field(metric: str, status: str, value: Any, reason: str) -> dict[str, Any]:
    if status not in WORK_AVOIDANCE_STATUS_VOCABULARY:
        raise ValueError(f"unknown work-avoidance status: {status}")
    return {
        f"work_avoidance_{metric}_status": status,
        f"work_avoidance_{metric}_value": value,
        f"work_avoidance_{metric}_reason": reason,
    }


def work_avoidance_metadata(
    engine: str,
    evidence: dict[str, Any] | None = None,
    row_status: str = "success",
) -> dict[str, Any]:
    metadata: dict[str, Any] = {
        "work_avoidance_schema_ref": "gar-flow-2d.work_avoidance_evidence.v1",
        "work_avoidance_status_vocabulary": ",".join(WORK_AVOIDANCE_STATUS_VOCABULARY),
        "work_avoidance_claim_allowed": False,
        "work_avoidance_claim_boundary": (
            "missing or not_available work-avoidance metrics cannot support performance, "
            "superiority, Spark-displacement, or best-default claims"
        ),
    }
    evidence = evidence or {}
    if not is_shardloom_engine(engine):
        reason = "external baseline rows are comparison-only, not ShardLoom work-avoidance evidence"
        for metric in WORK_AVOIDANCE_METRICS:
            metadata.update(work_avoidance_metric_field(metric, "not_applicable", None, reason))
        return metadata
    if row_status != "success":
        reason = f"row status is {row_status}; no ShardLoom work-avoidance runtime evidence emitted"
        for metric in WORK_AVOIDANCE_METRICS:
            metadata.update(work_avoidance_metric_field(metric, "unsupported", None, reason))
        return metadata
    if engine == "shardloom-direct-transient":
        metadata.update(
            work_avoidance_metric_field(
                "rows_avoided",
                "not_available",
                None,
                "direct transient smoke does not count skipped rows",
            )
        )
        metadata.update(
            work_avoidance_metric_field(
                "segments_pruned",
                "not_applicable",
                None,
                "direct transient smoke does not scan Vortex segments",
            )
        )
        metadata.update(
            work_avoidance_metric_field(
                "bytes_avoided",
                "not_available",
                None,
                "direct transient smoke does not measure avoided bytes",
            )
        )
        metadata.update(
            work_avoidance_metric_field(
                "encoded_vector_reuse",
                "not_applicable",
                None,
                "direct transient smoke is not a Vortex encoded-vector path",
            )
        )
        metadata.update(
            work_avoidance_metric_field(
                "pushdown_proof",
                "not_applicable",
                None,
                "direct transient smoke has no Vortex Scan pushdown proof",
            )
        )
        return metadata

    filter_pushdown = evidence.get("streaming_filter_pushdown_applied")
    projection_pushdown = evidence.get("streaming_projection_pushdown_applied")
    pushdown_measured = filter_pushdown is not None or projection_pushdown is not None
    metadata.update(
        work_avoidance_metric_field(
            "rows_avoided",
            "not_available",
            None,
            "current traditional rows do not count skipped rows separately from rows scanned/materialized",
        )
    )
    metadata.update(
        work_avoidance_metric_field(
            "segments_pruned",
            "not_available",
            None,
            "current traditional rows do not emit pruned segment counts",
        )
    )
    metadata.update(
        work_avoidance_metric_field(
            "bytes_avoided",
            "not_available",
            None,
            "current traditional rows do not emit avoided byte counts",
        )
    )
    metadata.update(
        work_avoidance_metric_field(
            "encoded_vector_reuse",
            "not_available",
            None,
            "current traditional rows do not measure encoded-vector reuse as a standalone counter",
        )
    )
    metadata.update(
        work_avoidance_metric_field(
            "pushdown_proof",
            "measured" if pushdown_measured else "not_available",
            f"filter={filter_pushdown};projection={projection_pushdown}"
            if pushdown_measured
            else None,
            "streaming filter/projection pushdown fields are emitted by ShardLoom evidence"
            if pushdown_measured
            else "pushdown proof fields were not emitted for this row",
        )
    )
    return metadata


def native_work_avoidance_status(
    value: Any,
    known: Any,
    measured_reason: str,
    unknown_reason: str,
) -> tuple[str, Any, str]:
    if str(known).lower() == "true":
        return "measured", value, measured_reason
    if str(known).lower() == "false":
        return "not_available", value, unknown_reason
    if value not in (None, "", "n/a"):
        return "measured", value, measured_reason
    return "not_available", None, unknown_reason


def add_native_work_avoidance_schema(row: dict[str, Any]) -> dict[str, Any]:
    rows_status, rows_value, rows_reason = native_work_avoidance_status(
        row.get("work_avoided_rows_not_scanned"),
        row.get("work_avoided_rows_not_scanned_known"),
        "vortex-run emitted rows-not-scanned work-avoidance evidence",
        "vortex-run did not emit a rows-not-scanned count for this primitive",
    )
    segments_status, segments_value, segments_reason = native_work_avoidance_status(
        row.get("work_avoided_segments_pruned"),
        row.get("work_avoided_segments_pruned_known"),
        "vortex-run emitted segment-prune work-avoidance evidence",
        "vortex-run did not emit a pruned-segment count for this primitive",
    )
    bytes_status, bytes_value, bytes_reason = native_work_avoidance_status(
        row.get("work_avoided_bytes_not_read"),
        row.get("work_avoided_bytes_not_read_known"),
        "vortex-run emitted bytes-not-read work-avoidance evidence",
        "vortex-run did not emit an avoided-byte count for this primitive",
    )
    decode_value = row.get("work_avoided_decode_avoided")
    materialization_value = row.get("work_avoided_materialization_avoided")
    encoded_status = (
        "measured"
        if decode_value not in (None, "", "n/a") or materialization_value not in (None, "", "n/a")
        else "not_available"
    )
    pushdown_value = (
        f"filter={row.get('filter_pushdown_applied')};"
        f"projection={row.get('projection_pushdown_applied')}"
    )
    pushdown_status = (
        "measured"
        if row.get("filter_pushdown_applied") not in (None, "", "n/a")
        or row.get("projection_pushdown_applied") not in (None, "", "n/a")
        else "not_available"
    )
    row.update(
        {
            "work_avoidance_schema_ref": "gar-flow-2d.work_avoidance_evidence.v1",
            "work_avoidance_status_vocabulary": ",".join(WORK_AVOIDANCE_STATUS_VOCABULARY),
            "work_avoidance_claim_allowed": False,
            "work_avoidance_claim_boundary": (
                "native microbenchmark work-avoidance counters are scoped evidence, not "
                "performance or superiority claims"
            ),
        }
    )
    row.update(work_avoidance_metric_field("rows_avoided", rows_status, rows_value, rows_reason))
    row.update(
        work_avoidance_metric_field(
            "segments_pruned", segments_status, segments_value, segments_reason
        )
    )
    row.update(work_avoidance_metric_field("bytes_avoided", bytes_status, bytes_value, bytes_reason))
    row.update(
        work_avoidance_metric_field(
            "encoded_vector_reuse",
            encoded_status,
            f"decode_avoided={decode_value};materialization_avoided={materialization_value}"
            if encoded_status == "measured"
            else None,
            "decode/materialization avoidance fields emitted by vortex-run"
            if encoded_status == "measured"
            else "encoded-vector reuse was not measured for this native row",
        )
    )
    row.update(
        work_avoidance_metric_field(
            "pushdown_proof",
            pushdown_status,
            pushdown_value if pushdown_status == "measured" else None,
            "filter/projection pushdown fields emitted by vortex-run"
            if pushdown_status == "measured"
            else "pushdown evidence was not emitted for this native row",
        )
    )
    return row


def micros_to_millis_field(value: Any) -> float | None:
    micros = parse_optional_int(value)
    return None if micros is None else round(micros / 1000.0, 4)


def source_read_scout_stage_metrics(
    evidence: dict[str, Any] | None = None,
    *,
    micros_to_millis: Callable[[str], float | None] | None = None,
    default_status: str = "not_reported",
) -> dict[str, Any]:
    evidence = evidence or {}

    def millis(field: str) -> float | None:
        if micros_to_millis is not None:
            return micros_to_millis(field)
        return micros_to_millis_field(evidence.get(field))

    return {
        "source_read_header_scout_millis": millis("source_read_header_scout_micros"),
        "source_read_header_scout_micros": parse_optional_int(
            evidence.get("source_read_header_scout_micros")
        ),
        "source_read_byte_acquisition_millis": millis(
            "source_read_byte_acquisition_micros"
        ),
        "source_read_byte_acquisition_micros": parse_optional_int(
            evidence.get("source_read_byte_acquisition_micros")
        ),
        "source_read_full_body_millis": millis("source_read_full_body_micros"),
        "source_read_full_body_micros": parse_optional_int(
            evidence.get("source_read_full_body_micros")
        ),
        "source_read_typed_decode_millis": millis("source_read_typed_decode_micros"),
        "source_read_typed_decode_micros": parse_optional_int(
            evidence.get("source_read_typed_decode_micros")
        ),
        "source_read_row_assembly_millis": millis("source_read_row_assembly_micros"),
        "source_read_row_assembly_micros": parse_optional_int(
            evidence.get("source_read_row_assembly_micros")
        ),
        "source_read_anomaly_quarantine_millis": millis(
            "source_read_anomaly_quarantine_micros"
        ),
        "source_read_anomaly_quarantine_micros": parse_optional_int(
            evidence.get("source_read_anomaly_quarantine_micros")
        ),
        "source_read_columnar_handoff_millis": millis(
            "source_read_columnar_handoff_micros"
        ),
        "source_read_columnar_handoff_micros": parse_optional_int(
            evidence.get("source_read_columnar_handoff_micros")
        ),
        "source_read_scout_status": evidence.get(
            "source_read_scout_status", default_status
        ),
        "source_read_scout_reuse_status": evidence.get(
            "source_read_scout_reuse_status", default_status
        ),
        "source_read_decode_status": evidence.get(
            "source_read_decode_status", default_status
        ),
        "source_read_projected_field_mask": evidence.get(
            "source_read_projected_field_mask", "0x00000000"
        ),
        "source_read_filter_field_mask": evidence.get(
            "source_read_filter_field_mask", "0x00000000"
        ),
        "source_read_decoded_columns": evidence.get(
            "source_read_decoded_columns", "none"
        ),
        "source_read_skipped_columns": evidence.get(
            "source_read_skipped_columns", "none"
        ),
        "source_read_decoded_column_count": parse_optional_int(
            evidence.get("source_read_decoded_column_count")
        )
        or 0,
        "source_read_skipped_column_count": parse_optional_int(
            evidence.get("source_read_skipped_column_count")
        )
        or 0,
        "source_read_row_materialization_status": evidence.get(
            "source_read_row_materialization_status", default_status
        ),
        "source_read_unsupported_shape_diagnostic": evidence.get(
            "source_read_unsupported_shape_diagnostic", default_status
        ),
    }


def vortex_scan_attribution_stage_metrics(
    evidence: dict[str, Any] | None = None,
    *,
    micros_to_millis: Callable[[str], float | None] | None = None,
    micros_to_int: Callable[[str], int | None] | None = None,
) -> dict[str, Any]:
    evidence = evidence or {}

    def millis(field: str) -> float | None:
        if micros_to_millis is not None:
            return micros_to_millis(field)
        return micros_to_millis_field(evidence.get(field))

    def micros(field: str) -> int | None:
        if micros_to_int is not None:
            return micros_to_int(field)
        return parse_optional_int(evidence.get(field))

    scan_chunk_iter_micros = micros("scan_chunk_iter_micros")
    if scan_chunk_iter_micros is None:
        scan_chunk_iter_micros = micros("vortex_chunk_iteration_micros")

    metrics = {
        "vortex_footer_open_millis": millis("vortex_footer_open_micros"),
        "vortex_footer_open_micros": micros("vortex_footer_open_micros"),
        "vortex_metadata_verify_millis": millis("vortex_metadata_verify_micros"),
        "vortex_metadata_verify_micros": micros("vortex_metadata_verify_micros"),
        "vortex_scan_open_millis": millis("vortex_scan_open_micros"),
        "vortex_scan_open_micros": micros("vortex_scan_open_micros"),
        "vortex_scenario_scan_millis": millis("vortex_scenario_scan_micros"),
        "vortex_scenario_scan_micros": micros("vortex_scenario_scan_micros"),
        "scan_chunk_iter_micros": scan_chunk_iter_micros,
        "vortex_projected_field_extract_micros": micros(
            "vortex_projected_field_extract_micros"
        ),
        "vortex_encoded_kernel_evidence_micros": micros(
            "vortex_encoded_kernel_evidence_micros"
        ),
        "operator_kernel_micros": micros("operator_kernel_micros"),
        "operator_finalize_micros": micros("operator_finalize_micros"),
        "result_assembly_micros": micros("result_assembly_micros"),
    }
    metrics.update(
        {
            field: parse_optional_int(evidence.get(field))
            for field in VORTEX_SCAN_COUNTER_FIELDS
        }
    )
    return metrics


